-fn build_scrollback(lines: usize, cols: u16) -> Scrollback {
-    let mut scrollback = Scrollback::new(lines);
-    for i in 0..lines {
-        let row = make_row(cols, i as u32);
-        let _ = scrollback.push_row(&row, i % 3 == 0);
-    }
-    scrollback
-}
