-            row: 0,
-            col: 0,
-            visible: true,
-            pending_wrap: false,
-            attrs: SgrAttrs::default(),
-            scroll_top: 0,
-            scroll_bottom: rows,
-            tab_stops,
-            charset_slots: [b'B'; 4],
-            active_charset: 0,
-            single_shift: None,
-        }
-    }
