-
-    /// Top of scroll region (inclusive).
-    pub fn scroll_top(&self) -> u16 {
-        self.scroll_top
-    }
-
-    /// Bottom of scroll region (exclusive).
-    pub fn scroll_bottom(&self) -> u16 {
