-        'o' => '\u{23BA}', // ⎺ scan line 1
-        'p' => '\u{23BB}', // ⎻ scan line 3
-        'q' => '\u{2500}', // ─ horizontal line
-        'r' => '\u{23BC}', // ⎼ scan line 7
-        's' => '\u{23BD}', // ⎽ scan line 9
-        't' => '\u{251C}', // ├ left tee
