-    ) -> DecisionReason {
-        if snapshot.output_hard_cap_duration_ms >= self.config.hard_cap_terminate_ms {
-            return DecisionReason::HardCapExceeded;
-        }
-        if chosen_action.is_none() {
-            return DecisionReason::Stable;
