-#[must_use]
-fn ratio_u32(numerator: u32, denominator: u32) -> f64 {
-    if denominator == 0 {
-        return f64::INFINITY;
-    }
-    f64::from(numerator) / f64::from(denominator)
-}
-
-#[must_use]
-fn clamp01(value: f64) -> f64 {
-    value.clamp(0.0, 1.0)
