-// ── Cell update ──────────────────────────────────────────────────────
-
-/// A single cell update at (row, col).
-///
-/// Used by GPU renderers for per-instance upload and by trace replayers
-/// for exact state reconstruction.
-#[derive(Debug, Clone, PartialEq, Eq)]
-pub struct CellUpdate {
-    pub row: u16,
-    pub col: u16,
-    pub cell: Cell,
-}
