-    let len = ((buf[1] as usize) << 16) | ((buf[2] as usize) << 8) | (buf[3] as usize);
-    if len > MAX_PAYLOAD_LEN {
-        return Err(CodecError::PayloadTooLarge { declared: len });
-    }
