-    let total = HEADER_LEN + len;
-    if buf.len() < total {
-        return Err(CodecError::Truncated {
-            expected: total,
-            available: buf.len(),
-        });
-    }
-    if buf.len() > total {
-        return Err(CodecError::TrailingBytes {
-            frame_len: total,
-            buffer_len: buf.len(),
-        });
-    }
